import React, { useState } from "react";
import { getSupabase } from "../../database/supabase";
import { removeVietnameseTones } from "../../ppm/util/vietToLatin";

type Field = {
  id: string;
  name: string;
  type: string;
  mapping?: string;
  helpText?: string;
  required?: boolean;
  placeholder?: string;
  options?: string[];
};

type FormData = {
  form: {
    id: string;
    title: string;
    fields: Field[];
  };
  successMessage?: string;
};

type RoutingData = Record<string, string>;

export default function TestSaveForms() {
  const [response, setResponse] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
    setLoading(true);

    const data: FormData = {
      form: {
        id: removeVietnameseTones("Ghi-Danh-Nhập-Học"),
        title: "Ghi Danh Nhập Học",
        fields: [
          { id: "field_0", name: "Họ và Tên", type: "short_answer", mapping: "name", required: true, placeholder: "Nhập họ và tên" },
          { id: "field_1", name: "Pháp Danh2", type: "short_answer", required: false, placeholder: "Nhập pháp danh" },
          { id: "field_2", name: "Ngày Sinh", type: "date", helpText: "Định dạng: dd/mm/yyyy", required: false, placeholder: "dd/mm/yyyy" },
          { id: "field_3", name: "Giới Tính", type: "multiple_choice", options: ["Nam", "Nữ"], required: true },
          { id: "field_4", name: "Email", type: "email_address", mapping: "email", required: true, placeholder: "example@email.com" },
          { id: "field_5", name: "Số Điện Thoại", type: "phone_number", required: true, placeholder: "### ### ####" },
          { id: "field_6", name: "Chương Trình Học", type: "dropdown", options: ["Sơ Cấp", "Trung Cấp", "Cao Đẳng"], required: true },
          { id: "field_7", name: "Hình Thức Tham Gia", type: "dropdown", options: ["Trực Tiếp", "Trực Tuyến"], required: true },
        ],
      },
      successMessage: "Thank you!",
    };

    const routing: RoutingData = {
      "chuong-trinh-thien": "chuong-trinh-thien"
    };

    try {
      const supabase = await getSupabase();
      const token = (supabase as any).supabaseKey ?? "";

      // 👇 FORCE THROUGH LOCAL PROXY (CORS BYPASS)
      const res = await fetch(
        "https://yvbanllkrinkckegmuua.supabase.co/functions/v1/save-forms-hardcopy-to-github",
        {
          method: "POST",
          headers: {
            "Authorization": `Bearer ${token}`,
            "Content-Type": "application/json",
          },
          body: JSON.stringify({ data, routing }),
        }
      );

      const json = await res.json();
      setResponse(json);
    } catch (err: any) {
      setResponse({ error: err.message });
    }

    setLoading(false);
  };

  return (
    <div style={{ padding: "2rem", fontFamily: "sans-serif" }}>
      <h1>Test Save Forms Hardcopy to GitHub</h1>
      <button onClick={handleSend} disabled={loading}>
        {loading ? "Sending..." : "Send to Supabase Function"}
      </button>

      {response && (
        <pre
          style={{
            marginTop: "2rem",
            padding: "1rem",
            background: "#f0f0f0",
            whiteSpace: "pre-wrap",
          }}
        >
          {JSON.stringify(response, null, 2)}
        </pre>
      )}
    </div>
  );
}